// ============================================================
// WoulfAI — Per-Agent Onboarding Step Configurations
// Generated by install-onboarding.js
// ============================================================
// Each agent defines its own onboarding "sprint" — the minimum
// steps to get real data flowing and deliver the "Aha Moment."

export interface OnboardingStep {
  id: string;
  title: string;
  description: string;
  type: 'form' | 'integration' | 'upload' | 'verify' | 'success';
  fields?: { name: string; label: string; type: string; required?: boolean; placeholder?: string }[];
  integrationKey?: string; // 'odoo' | 'hubspot' | 'google' | 'csv'
  ahaMessage?: string;
}

export interface AgentOnboardingConfig {
  agentId: string;
  agentName: string;
  icon: string;
  category: 'saas' | '3pl';
  estimatedMinutes: number;
  steps: OnboardingStep[];
}

