export function getOnboardingConfig(agentId: string): AgentOnboardingConfig | undefined {
  return ONBOARDING_CONFIGS[agentId];
}

export function getAllAgentIds(): string[] {
  return Object.keys(ONBOARDING_CONFIGS);
}
